(window.courseContentFiles = window.courseContentFiles || {})["000010/0001"] = "<!DOCTYPE html>\n<html lang=\"bg\">\n<head>\n  <meta charset=\"UTF-8\">\n  <meta name=\"viewport\" content=\"width=device-width, initial-scale=1.0\">\n  <title>1</title>\n  <link rel=\"stylesheet\" href=\"https://cdn.jsdelivr.net/npm/katex@0.16.4/dist/katex.min.css\">\n  <style>\n    body { \n      font-family: \"Open Sans\", Arial, sans-serif; \n      max-width: 1550px; \n      margin: 0.5rem auto; \n      padding: 0 1rem; \n      line-height: 1.6; \n      color: #1f2937; \n    }\n    h1, h2, h3, h4 { \n      font-weight: 600; \n      margin-top: 0.7em;\n      margin-bottom: 0;\n      color: #588157;\n    }\n    h1 { font-size: 1.65em; }\n    h2 { font-size: 1.3em; }\n    h3 { font-size: 1.1em; margin-bottom: 0; }\n    h4 { font-size: 1.05em; margin-bottom: 0; }\n    h1 + h2, h1 + h3, h1 + h4, h2 + h3, h2 + h4, h3 + h4 { margin-top: 0.1em; }\n    p { \n      margin: 0.3em 0; \n      white-space: pre-wrap;\n    }\n    hr {\n      margin: 0.45em 0 0.2em;\n    }\n    hr + h1,\n    hr + h2,\n    hr + h3,\n    hr + h4 {\n      margin-top: 0.2em;\n    }\n    hr + p,\n    hr + ul,\n    hr + ol,\n    hr + blockquote,\n    hr + pre,\n    hr + table {\n      margin-top: 0.08em;\n    }\n    p + ul, p + ol { margin-top: 0.2em; }\n    h1 + p, h2 + p, h3 + p, h4 + p,\n    h1 + ul, h2 + ul, h3 + ul, h4 + ul,\n    h1 + ol, h2 + ol, h3 + ol, h4 + ol { \n      margin-top: 0; \n    }\n    ul, ol { \n      margin: 0.2em 0; \n      padding-left: 1.5em; \n      list-style-position: outside;\n    }\n    li { margin: 0.2em 0; }\n    li p {\n      margin: 0;\n      padding: 0;\n      display: inline;\n    }\n    li > ul, li > ol {\n      margin: 0.15em 0 0 0;\n      padding-left: 1.5em;\n    }\n    ul ul, ul ol, ol ul, ol ol {\n      margin-top: 0.1em;\n      padding-left: 1.5em;\n    }\n    ul ul { list-style-type: circle; }\n    ul ul ul { list-style-type: square; }\n    strong { font-weight: 600; }\n    em { font-style: italic; }\n    code { \n      background: rgba(218, 215, 205, 0.3); \n      padding: 2px 6px; \n      border-radius: 3px; \n      font-family: \"Courier New\", monospace; \n      font-size: 0.9em; \n    }\n    pre {\n      background: rgba(255, 255, 255, 0.5);\n      padding: 12px;\n      border-radius: 4px;\n      overflow-x: auto;\n      margin: 0.5em 0;\n      font-family: \"Courier New\", monospace;\n    }\n    pre code {\n      background: none;\n      padding: 0;\n    }\n    blockquote {\n      border-left: 3px solid #588157;\n      padding-left: 1em;\n      margin: 0.5em 0;\n      font-style: italic;\n      color: #166534;\n    }\n    table { \n      border-collapse: collapse; \n      margin: 0.75em 0; \n      width: 100%; \n      table-layout: auto;\n    }\n    th, td { \n      border: 1px solid rgba(2, 2, 2, 0.2);\n      padding: 6px 10px; \n      text-align: left; \n      vertical-align: top;\n      height: 24px;\n      line-height: 1.2;\n    }\n    thead th { \n      background: rgba(88, 129, 87, 0.13); \n      font-weight: 600; \n    }\n    tbody tr:nth-child(odd) { \n      background: rgba(88, 129, 87, 0.06); \n    }\n    /* Image alignment rules for exported content and md-viewer */\n    img[data-align=\"left\"] {\n      display: block;\n      margin: 8px auto 8px 0;\n    }\n    img[data-align=\"center\"] {\n      display: block;\n      margin: 8px auto;\n    }\n    img[data-align=\"right\"] {\n      display: block;\n      margin: 8px 0 8px auto;\n    }\n    .audio-link-inline {\n      display: inline-flex;\n      align-items: center;\n      gap: 8px;\n      margin: 0.2em 0;\n      max-width: 100%;\n      vertical-align: middle;\n    }\n    .audio-link-icon {\n      width: 28px;\n      height: 28px;\n      border: 1px solid #588157;\n      border-radius: 999px;\n      background: #f0f7f0;\n      color: #2f5d50;\n      cursor: pointer;\n      font-size: 14px;\n      line-height: 1;\n      display: inline-flex;\n      align-items: center;\n      justify-content: center;\n      flex: 0 0 auto;\n    }\n    .audio-link-inline audio {\n      position: absolute;\n      width: 1px;\n      height: 1px;\n      opacity: 0;\n      overflow: hidden;\n      pointer-events: none;\n    }\n    .audio-link-icon img {\n      width: 14px;\n      height: 14px;\n      object-fit: contain;\n      pointer-events: none;\n    }\n    a {\n      color: inherit; /* Changed to inherit */\n      text-decoration: underline;\n    }\n    a:hover {\n      color: #74b673;\n    }\n    /* Keep <p> tags inside list items on same line (as they appear in editor) */\n    li p {\n      margin: 0 !important;\n      padding: 0 !important;\n      display: inline !important;\n    }\n    /* Prevent nested list paragraph issues */\n    li > ul,\n    li > ol {\n      margin: 0.15em 0 0 0;\n      padding-left: 1.5em;\n    }\n    /* Ensure list structure is clean */\n    ul ul, ul ol,\n    ol ul, ol ol {\n      margin-top: 0.1em;\n      padding-left: 1.5em;\n    }\n    @media (max-width: 768px) {\n      body {\n        margin: 0.5rem 0;\n        padding: 0 0.5rem;\n        font-size: 16px;\n      }\n      h1 { font-size: 1.65em; }\n      h2 { font-size: 1.3em; }\n      h3 { font-size: 1.1em; }\n      p { margin: 0.3em 0; }\n      ul, ol { padding-left: 1.5em; }\n      li { margin: 0.2em 0; }\n      table { font-size: 0.9em; }\n      th, td { padding: 6px 10px; }\n    }\n    .editor-note {\n      text-decoration: underline dotted #a3b18a;\n      text-decoration-thickness: 2px;\n      text-underline-offset: 2px;\n      text-decoration-skip-ink: none;\n      cursor: help;\n      position: relative;\n    }\n    .note-tooltip {\n      display: none;\n      position: absolute;\n      background-color: #f0f7f0;\n      color: #1f2937;\n      border: 1px solid #588157;\n      border-radius: 4px;\n      padding: 8px 12px;\n      width: fit-content;\n      max-width: min(700px, calc(100vw - 20px));\n      max-height: calc(100vh - 20px);\n      overflow: auto;\n      box-sizing: border-box;\n      box-shadow: 0 2px 8px rgba(0,0,0,0.2);\n      z-index: 10000;\n      font-size: 0.9em;\n      line-height: 1.4;\n      word-wrap: break-word;\n    }\n    .note-tooltip ul, .note-tooltip ol {\n      margin: 0 !important;\n      padding-left: 20px !important;\n    }\n    .note-tooltip li {\n      margin: 0 0 0.1em 0 !important;\n      padding: 0 !important;\n      line-height: 1.2 !important;\n    }\n    .note-tooltip li:last-child {\n      margin-bottom: 0 !important;\n    }\n    .note-tooltip .note-table-scroll {\n      overflow-x: hidden;\n      margin: 0.3em 0;\n      max-width: 100%;\n    }\n    .note-tooltip table {\n      border-collapse: collapse;\n      width: 100%;\n      max-width: 100%;\n      min-width: 0;\n      table-layout: fixed;\n      background: #ffffff;\n    }\n    .note-tooltip th,\n    .note-tooltip td {\n      border: 1px solid rgba(88, 129, 87, 0.35);\n      padding: 4px 8px;\n      text-align: left;\n      vertical-align: top;\n      line-height: 1.3;\n      white-space: normal;\n      overflow-wrap: anywhere;\n      word-break: break-word;\n    }\n    .note-tooltip thead th {\n      background: rgba(88, 129, 87, 0.12);\n      font-weight: 600;\n    }\n  </style>\n  <script>\n    document.addEventListener('DOMContentLoaded', function() {\n      const tooltip = document.createElement('div');\n      tooltip.className = 'note-tooltip';\n      document.body.appendChild(tooltip);\n\n      function parseNoteMarkdown(text) {\n        if (!text) return '';\n        \n        const splitTableCells = function(line) {\n          return String(line || '')\n            .trim()\n            .replace(/^\\|/, '')\n            .replace(/\\|$/, '')\n            .split('|')\n            .map(function(cell) { return cell.trim(); });\n        };\n\n        const isTableSeparatorLine = function(line) {\n          const cells = splitTableCells(line);\n          return cells.length > 0 && cells.every(function(cell) {\n            return /^:?-{3,}:?$/.test(cell);\n          });\n        };\n\n        const getTableAlignment = function(cell) {\n          if (/^:-{3,}:$/.test(cell)) return 'center';\n          if (/^-{3,}:$/.test(cell)) return 'right';\n          if (/^:-{3,}$/.test(cell)) return 'left';\n          return '';\n        };\n\n        let lines = text.split('\\n');\n        let html = [];\n        let stack = [];\n        \n        for (let i = 0; i < lines.length; i++) {\n          let line = lines[i];\n          \n          let indentMatch = line.match(/^(\\s*)/);\n          let indent = indentMatch ? indentMatch[1].length : 0;\n          let content = line.trim();\n\n          const nextLine = i + 1 < lines.length ? lines[i + 1].trim() : '';\n          const maybeTableHeader = content.includes('|') && splitTableCells(content).length >= 2;\n          const maybeTableSeparator = nextLine.includes('|') && isTableSeparatorLine(nextLine);\n\n          if (maybeTableHeader && maybeTableSeparator) {\n            while (stack.length > 0) {\n              let closed = stack.pop();\n              html.push('</' + closed.type + '>');\n            }\n\n            const headerCells = splitTableCells(content);\n            const alignCells = splitTableCells(nextLine);\n\n            html.push('<div class=\"note-table-scroll\"><table><thead><tr>');\n            headerCells.forEach(function(cell, idx) {\n              const align = getTableAlignment(alignCells[idx] || '');\n              const alignAttr = align ? ' style=\"text-align:' + align + ';\"' : '';\n              html.push('<th' + alignAttr + '>' + cell + '</th>');\n            });\n            html.push('</tr></thead><tbody>');\n\n            i += 2;\n            while (i < lines.length) {\n              const rowLine = lines[i].trim();\n              if (!rowLine || !rowLine.includes('|')) break;\n              if (isTableSeparatorLine(rowLine)) {\n                i++;\n                continue;\n              }\n\n              const rowCells = splitTableCells(rowLine);\n              if (rowCells.length === 0) {\n                i++;\n                continue;\n              }\n\n              html.push('<tr>');\n              rowCells.forEach(function(cell, idx) {\n                const align = getTableAlignment(alignCells[idx] || '');\n                const alignAttr = align ? ' style=\"text-align:' + align + ';\"' : '';\n                html.push('<td' + alignAttr + '>' + cell + '</td>');\n              });\n              html.push('</tr>');\n              i++;\n            }\n\n            html.push('</tbody></table></div>');\n            i--;\n            continue;\n          }\n          \n          let isUl = /^[-*]\\s+(.+)/.test(content);\n          let isOl = /^\\d+\\.\\s+(.+)/.test(content);\n          \n          if (isUl || isOl) {\n            let listType = isUl ? 'ul' : 'ol';\n            let match = isUl ? content.match(/^[-*]\\s+(.+)/) : content.match(/^\\d+\\.\\s+(.+)/);\n            let itemText = match[1];\n            \n            if (stack.length === 0) {\n              stack.push({ type: listType, indent: indent });\n              html.push('<' + listType + '>');\n            } else {\n              let last = stack[stack.length - 1];\n              \n              if (indent > last.indent) {\n                stack.push({ type: listType, indent: indent });\n                html.push('<' + listType + '>');\n              } else if (indent < last.indent) {\n                while (stack.length > 0 && stack[stack.length - 1].indent > indent) {\n                  let closed = stack.pop();\n                  html.push('</' + closed.type + '>');\n                }\n                if (stack.length === 0 || stack[stack.length - 1].indent !== indent) {\n                   stack.push({ type: listType, indent: indent });\n                   html.push('<' + listType + '>');\n                } else if (stack[stack.length - 1].type !== listType) {\n                   let closed = stack.pop();\n                   html.push('</' + closed.type + '>');\n                   stack.push({ type: listType, indent: indent });\n                   html.push('<' + listType + '>');\n                }\n              } else {\n                if (last.type !== listType) {\n                  let closed = stack.pop();\n                  html.push('</' + closed.type + '>');\n                  stack.push({ type: listType, indent: indent });\n                  html.push('<' + listType + '>');\n                }\n              }\n            }\n            html.push('<li>' + itemText + '</li>');\n          } else {\n            if (content !== '') {\n               while (stack.length > 0) {\n                 let closed = stack.pop();\n                 html.push('</' + closed.type + '>');\n               }\n            }\n            if (/^(?:---|\\*\\*\\*|___)$/.test(content)) {\n              html.push('<hr>');\n            } else if (/^#{1,4}\\s+/.test(content)) {\n              const headingMatch = content.match(/^(#{1,4})\\s+(.+)$/);\n              if (headingMatch) {\n                const level = headingMatch[1].length;\n                html.push('<h' + level + '>' + headingMatch[2] + '</h' + level + '>');\n              }\n            } else if (content) {\n              html.push(content + '<br>');\n            } else {\n              html.push('<br>');\n            }\n          }\n        }\n        \n        while (stack.length > 0) {\n          let closed = stack.pop();\n          html.push('</' + closed.type + '>');\n        }\n        \n        let result = html.join('')\n          .replace(/!\\[(.*?)\\]\\((.*?)\\)/g, '<img src=\"$2\" alt=\"$1\">')\n          .replace(/\\*\\*(.+?)\\*\\*/g, '<strong>$1</strong>')\n          .replace(/__(.+?)__/g, '<strong>$1</strong>')\n          .replace(/\\*(.+?)\\*/g, '<em>$1</em>')\n          .replace(/_(.+?)_/g, '<em>$1</em>')\n          .replace(/`(.+?)`/g, '<code>$1</code>')\n          .replace(/\\[(.+?)\\]\\((.+?)\\)/g, '<a href=\"$2\" target=\"_blank\">$1</a>');\n        \n        result = result\n          .replace(/<br><ul>/g, '<ul>')\n          .replace(/<br><ol>/g, '<ol>')\n          .replace(/</ul><br>/g, '</ul>')\n          .replace(/</ol><br>/g, '</ol>');\n        \n        return result;\n      }\n\n      document.body.addEventListener('mouseover', function(e) {\n        if (e.target.classList.contains('editor-note')) {\n          const note = e.target.dataset.note;\n          if (note) {\n            tooltip.innerHTML = parseNoteMarkdown(note);\n            tooltip.style.display = 'block';\n            const rect = e.target.getBoundingClientRect();\n            const tooltipRect = tooltip.getBoundingClientRect();\n            const pageX = window.scrollX || window.pageXOffset;\n            const pageY = window.scrollY || window.pageYOffset;\n            const maxLeft = pageX + window.innerWidth - tooltipRect.width - 10;\n            const minLeft = pageX + 10;\n\n            let left = rect.left + pageX;\n            if (left > maxLeft) left = maxLeft;\n            if (left < minLeft) left = minLeft;\n\n            let top = rect.bottom + pageY + 6;\n            const maxTop = pageY + window.innerHeight - tooltipRect.height - 10;\n            if (top > maxTop) {\n              top = rect.top + pageY - tooltipRect.height - 6;\n            }\n            if (top < pageY + 10) top = pageY + 10;\n\n            tooltip.style.left = left + 'px';\n            tooltip.style.top = top + 'px';\n          }\n        }\n      });\n\n      document.body.addEventListener('mouseout', function(e) {\n        if (e.target.classList.contains('editor-note')) {\n          setTimeout(() => {\n            if (!tooltip.matches(':hover')) {\n              tooltip.style.display = 'none';\n            }\n          }, 100);\n        }\n      });\n\n      tooltip.addEventListener('mouseleave', function() {\n        tooltip.style.display = 'none';\n      });\n    });\n  </script>\n</head>\n<body>\n<h1 style=\"text-align: center\">Въпроси за колоквиум</h1><p><strong>Кратковременната циклоплегия се постига с:</strong></p><ul><li><strong><span style=\"color: rgb(255, 0, 0)\">Мидрум</span></strong></li><li>Тимолол</li><li>Атропин</li><li>Циклопентолат</li><li>Тобрекс</li></ul><p><strong>Адаптометрията дава информация за:</strong></p><ul><li><strong><span style=\"color: rgb(255, 0, 0)\">Нощното зрение</span></strong></li><li>Централното зрение</li><li>Периферното зрение</li><li>Наличие на заболяване</li><li>Рефракцията</li></ul><p><strong>Конюнктивитът на новороденото може да бъде предизвикан от всичко, с изключение на:</strong></p><ul><li><strong><span style=\"color: rgb(255, 0, 0)\">Интоксикации</span></strong></li><li>Гонококи</li><li>Хламидии</li><li>Стафилококи</li><li>Херпес симплекс</li></ul><p><strong>Тежко изгаряне с контрактура на бузата предизвиква:</strong></p><ul><li><strong><span style=\"color: rgb(255, 0, 0)\"><p>Ектропион</p><br></span></strong></li><li>Всичко посочено</li><li>Птоза</li><li>Ретракция</li><li>Ентропион</li></ul><p><strong>Херпетичният кератит:</strong></p><ul><li><strong><span style=\"color: rgb(255, 0, 0)\">Всичко изброено</span></strong></li><ul><li>Лекува се с ацикловир</li><li>Рецидивира при отслабване на имунитета</li><li>Може да завърши с левкома</li><li>Може да се прояви като дендритна язва</li></ul></ul><p><strong>Детската катаракта:</strong></p><ul><li><strong><span style=\"color: rgb(255, 0, 0)\">Лекува се само оперативно</span></strong></li><li>Може да се излекува с капки</li><li>Не засяга зрението</li><li>Протича задължително с повишено налягане</li><li>Често е съпроводена с червено око</li></ul><p><strong>Сенилната катаракта:</strong></p><ul><li><strong><span style=\"color: rgb(255, 0, 0)\">Всичко посочено</span></strong></li><ul><li>Лекува се само оперативно</li><li>Дължи се на УВ увреждане</li><li>Проявява се с астигматизъм</li><li>Може да се развие двустранно</li></ul></ul><p><strong>Буфталм се нарича:</strong></p><ul><li><strong><span style=\"color: rgb(255, 0, 0)\">Увеличената очна ябълка при вродена глаукома</span></strong></li><li>Увеит при вродена глаукома</li><li>Кератита при вродена глаукома</li><li>Конюнктивита при вродена глаукома</li><li>Сълзенето при вродена глаукома</li></ul><p><strong>Според основната класификация, откритоъгълната глаукома бива:</strong></p><ul><li><strong><span style=\"color: rgb(255, 0, 0)\">Първична и вторична</span></strong></li><li>Откритоъгълна, закритоъгълна и вродена</li><li>Увеитна, неувеитна и смесена</li><li>Исхемична и неисхемична</li><li>Остра, подостра и хронична</li></ul><p><strong>Първичната закритоъгълна глаукома може да доведе до увреждане на:</strong></p><ul><li><strong><span style=\"color: rgb(255, 0, 0)\">Всичко посочено</span></strong></li><ul><li>Зрителния нерв</li><li>Ириса</li><li>Роговицата</li><li>Лещата</li></ul></ul><p><strong>Първичната закритоъгълна глаукома (глаукомен пристъп) се характеризира с всички посочени признаци, с изключение на:</strong></p><ul><li><strong><span style=\"color: rgb(255, 0, 0)\">Неоваскуларизация на ириса</span></strong></li><li>Оток на роговицата</li><li>Повишено налягане</li><li>Конгестивна инекция</li><li>Плитка предна камера</li></ul><p><strong>Размерът на роговицата при буфталм е:</strong></p><ul><li><strong><span style=\"color: rgb(255, 0, 0)\">Над 12 мм</span></strong></li><li>Под 10 мм</li><li>Над 1 см</li><li>Различен в зависимост от вида на глаукомата</li><li>Няма значение</li></ul><p><strong>Еписклеритът е:</strong></p><ul><li><strong><span style=\"color: rgb(255, 0, 0)\">Възпаление на еписклерата</span></strong></li><li>Инфекция на склерата</li><li>Травма на повърхностната част на склерата</li><li>Системно заболяване</li><li>Всичко посочено</li></ul><p><strong>Диабетната ретинопатия в началния стадий (непролиферативна диабетна ретинопатия):</strong></p><ul><li><strong><span style=\"color: rgb(255, 0, 0)\">Изисква консултация с офталмолог</span></strong></li><li>Лекува се с лазер</li><li>Не зависи от давността на диабета</li><li>Не зависи от контрола на диабета</li><li>Всичко посочено</li></ul><p><strong>Малигненият меланом на увеята може да произлиза от:</strong></p><ul><li><strong><span style=\"color: rgb(255, 0, 0)\">Никое от изброените</span></strong></li><ul><li>Съдовете на ириса</li><li>Ретината</li><li>Цилиарните нерви</li><li>Всички изброени</li></ul></ul><p><strong>Зениците могат да бъдат разширени за най-кратко с:</strong></p><ul><li><strong><span style=\"color: rgb(255, 0, 0)\">Адреналин</span></strong></li><li>Мидриум</li><li>Атропин</li><li>Цикложил</li><li>Пилокарпин</li></ul><p><strong>Зрителната острота дава информация за:</strong></p><ul><li><strong><span style=\"color: rgb(255, 0, 0)\">Централното зрение</span></strong></li><li>Периферното зрение</li><li>Нощното зрение</li><li>Наличие на заболяване</li><li>Рефракцията</li></ul><p><strong>Конюнктивитът на новороденото:</strong></p><ul><li><strong><span style=\"color: rgb(255, 0, 0)\">Изисква консултация със специалист по очни болести</span></strong></li><li>Изисква незабавно лечение със системни антибиотици</li><li>Е нормално състояние</li><li>Не се среща в България</li><li>Отзвучава спонтанно</li></ul><p><strong>Заболяването на щитовидната жлеза предизвиква:</strong></p><ul><li><strong><span style=\"color: rgb(255, 0, 0)\"><p>Ретракция</p><br></span></strong></li><li>Всичко посочено</li><li>Птоза</li><li>Ектропион</li><li>Ентропион</li></ul><p><strong>Херпетичният кератит:</strong></p><ul><li><strong><span style=\"color: rgb(255, 0, 0)\"><p>Може да се прояви като дендритна язва</p><br></span></strong></li><li>Се развива само веднъж и никога не рецидивира</li><li>Се лекува с кортикостероиди</li><li>Изисква оперативно лечение</li><li>Всичко изброено</li></ul><p><strong>Според основната класификация, глаукомата бива:</strong></p><ul><li><strong><span style=\"color: rgb(255, 0, 0)\">Откритоъгълна, закритоъгълна и вродена</span></strong></li><li>Увеитна, неувеитна и смесена</li><li>Начална, напреднала и зряла</li><li>Исхемична и неисхемична</li><li>Остра, подостра и хронична</li></ul><p><strong>Птеригиумът (външно перде):</strong></p><ul><li><strong><span style=\"color: rgb(255, 0, 0)\">Всичко посочено</span></strong></li><ul><li>Лекува се само оперативно</li><li>Дължи се на УВ увреждане</li><li>Предизвиква астигматизъм</li><li>Може да се развие двустранно</li></ul></ul><p><strong>Зениците могат да бъдат разширени за 1 седмица с:</strong></p><ul><li><strong><span style=\"color: rgb(255, 0, 0)\">Атропин</span></strong></li><li>Мидрум</li><li>Тимолол</li><li>Цикложил</li><li>Тобрекс</li></ul><p><strong>Първичната откритоъгълна глаукома е заболяване, водещо до увреждане на:</strong></p><ul><li><strong><span style=\"color: rgb(255, 0, 0)\">Зрителния нерв</span></strong></li><li>Очната ябълка</li><li>Роговицата</li><li>Лещата</li><li>Стъкловидното тяло</li></ul><p><strong>Увеитът е:</strong></p><ul><li><strong><span style=\"color: rgb(255, 0, 0)\">Възпаление на увеята</span></strong></li><li>Инфекция на конюнктивата</li><li>Травма на ретината</li><li>Системно заболяване</li><li>Всичко посочено</li></ul><p><strong>Диабетната ретинопатия в напреднал стадий:</strong></p><ul><li><strong><span style=\"color: rgb(255, 0, 0)\"><p>Изисква консултация с офталмолог</p><br></span></strong></li><li>Всичко посочено</li><li>Лекува се с медикаменти</li><li>Не зависи от давността на диабета</li><li>Не зависи от контрола на диабета</li></ul><p><strong>Малигненият меланом на увеята може да произлиза от:</strong></p><ul><li><strong><span style=\"color: rgb(255, 0, 0)\">Всички изброени</span></strong></li><ul><li>Ириса</li><li>Хороидеята</li><li>Цилиарното тяло</li><li>Никое от изброените</li></ul></ul><p><strong>Зениците могат да се разширят за 24 часа с:</strong></p><ul><li><strong><span style=\"color: rgb(255, 0, 0)\">Мидрум</span></strong></li><li>Тимолол</li><li>Атропин</li><li>Пилокарпин (<span style=\"color: rgb(0, 176, 80)\">миотик</span>)</li><li>Тобрекс</li></ul><p><strong>Периметърът дава информация за:</strong></p><ul><li><strong><span style=\"color: rgb(255, 0, 0)\">Периферното зрение</span></strong></li><li>Централното зрение</li><li>Нощното зрение</li><li>Наличие на заболяване</li><li>Рефракцията</li></ul><p><strong>Конюнктивитът на новороденото може да бъде предизвикан от:</strong></p><ul><li><strong><span style=\"color: rgb(255, 0, 0)\">Всичко изброено</span></strong></li><ul><li>Гонококи</li><li>Хламидии</li><li>Интоксикация</li><li>Стафилококи</li></ul></ul><p><strong>Миастенията предизвиква:</strong></p><ul><li><strong><span style=\"color: rgb(255, 0, 0)\">Птоза</span></strong></li><li>Ретракция</li><li>Ектропион</li><li>Ентропион</li><li>Всичко посочено</li></ul><p><strong>Орбитата е изградена от:</strong></p><ul><li><strong><span style=\"color: rgb(255, 0, 0)\">7 </span><span style=\"color: rgb(255, 0, 0)\">кости</span></strong></li><li>3 кости</li><li>5 кости</li><li>6 кости</li><li>10 кости</li></ul><p><strong>M. levator palpebrae superioris се инервира от:</strong></p><ul><li><strong><span style=\"color: rgb(255, 0, 0)\">N. oculomotorius</span></strong></li><li>N. facialis</li><li>N. ophthalmicus</li><li>N. trochlearis</li><li>N. abducens</li></ul><p><strong>Слъзният филм се състои от:</strong></p><ul><li><strong><span style=\"color: rgb(255, 0, 0)\">Три слоя</span></strong></li><li>Два слоя</li><li>Пет слоя</li><li>Един слой</li><li>Шест слоя</li></ul><p><strong>Муциновият слой на слъзния филм се секретира от:</strong></p><ul><li><strong><span style=\"color: rgb(255, 0, 0)\">Жлезите на Манц и криптите на Хенле</span></strong></li><li>Мейбомиевите жлези</li><li>Жлезите на Цайс</li><li>Жлези на Краузе и Волфриг</li><li>Слъзната жлеза</li></ul><p><strong>Хистологично роговицата се състои от:</strong></p><ul><li><strong><span style=\"color: rgb(255, 0, 0)\">Пет слоя</span></strong></li><li>Един слой</li><li>Два слоя</li><li>Три слоя</li><li>Четири слоя</li></ul><p><strong>Инервацията на горен прав мускул е от:</strong></p><ul><li><strong><span style=\"color: rgb(255, 0, 0)\">N. oculomotorius</span></strong></li><li>N. abducens</li><li>N. trochlearis</li><li>N. opthalmicus</li><li>Нито един от посочените</li></ul><p><strong>Електронномикроскопски ретината се състои от:</strong></p><ul><li><strong><span style=\"color: rgb(255, 0, 0)\">Десет слоя</span></strong></li><li>Осем слоя</li><li>Пет слоя</li><li>Седем слоя</li><li>Шест слоя</li></ul><p><strong>В ретината се намират:</strong></p><ul><li><strong><span style=\"color: rgb(255, 0, 0)\">Три неврона на зрителния анализатор</span></strong></li><li>Два неврона на зрителния анализатор</li><li>Четири неврона на зрителния анализатор</li><li>Еди неврон на зрителния анализатор</li><li>Нито един</li></ul><p><strong>Папиломакуленото снопче се разполага в:</strong></p><ul><li><strong><span style=\"color: rgb(255, 0, 0)\">Темпоралната част от диска на зрителния нерв</span></strong></li><li>Назалната част от диска на зрителния нерв</li><li>Горната част от диска на зрителния нерв</li><li>Долната част от диска на зрителния нерв</li><li>Във всички квадранти</li></ul><p><strong>Периферната част на зрителния анализатор свършва в:</strong></p><ul><li><strong><span style=\"color: rgb(255, 0, 0)\">Диска на зрителния нерв</span></strong></li><li>Латералното коленчато тяло</li><li>Хиазмата</li><li>Радиацио оптика</li><li>Нито един от посочените</li></ul><p><strong>Адаптометрията е метод за изследване на:</strong></p><ul><li><strong><span style=\"color: rgb(255, 0, 0)\">Светлоусещане</span></strong></li><li>Цветоусещане</li><li>Зрителна острота</li><li>Измерване на вътреочното налягане</li><li>Нито един от посочените</li></ul><p><strong>Хиперметропията се коригира с:</strong></p><ul><li><strong><span style=\"color: rgb(255, 0, 0)\">Събирателни лещи</span></strong></li><li>Разсейващи лещи</li><li>Цилиндрични лещи</li><li>Всички изброени</li><li>Нищо от изброените</li></ul><p><strong>Зрителният анализатор на човека може да възприема светлинни лъчи с дължина на вълната от:</strong></p><ul><li><strong><span style=\"color: rgb(255, 0, 0)\">390 до 760 nm</span></strong></li><li>300 до 500 nm</li><li>500 до 700 nm</li><li>100 до 200 nm</li><li>Над 760 nm</li></ul><p><strong>Angulus minimum visible е равен на:</strong></p><ul><li><strong><span style=\"color: rgb(255, 0, 0)\">Пет минути</span></strong></li><li>Един градус</li><li>Три минути</li><li>Една минута</li><li>Четири минути</li></ul><p><strong>Изследване на зрителната острота със зрителни таблици се извършва от:</strong></p><ul><li><strong><span style=\"color: rgb(255, 0, 0)\">Пет метра</span></strong></li><li>Един метър</li><li>Два метра</li><li>Три метра</li><li>Четири метра</li></ul><p><strong>При emetropia punctum remotum се намира на:</strong></p><ul><li><strong><span style=\"color: rgb(255, 0, 0)\">В безкрайността</span></strong></li><li>Три метра</li><li>Два метра</li><li>Един метър</li><li>Четири метра</li></ul><p><strong>При миопия от -1D punctum remotum се намира на:</strong></p><ul><li><strong><span style=\"color: rgb(255, 0, 0)\">Четири метра</span></strong></li><li>Три метра</li><li>В безкрайността</li><li>Два метра</li><li>Един метър</li></ul><p><strong>Корекцията на късогледството се извършва с:</strong></p><ul><li><strong><span style=\"color: rgb(255, 0, 0)\">Най-слабата минусова леща, която дава зрителна острота 1.0</span></strong></li><li>Най-силната минусова леща, която дава зрителна острота 1.0</li><li>С тази леща, с която се вижда най-добре</li><li>Минусова леща по преценка на офталмолога</li><li>Нито един от посочените</li></ul><p><strong>При скиаскопия се търси:</strong></p><ul><li><strong><span style=\"color: rgb(255, 0, 0)\"><p>Фундусов рефлекс</p><br></span></strong></li><li>Пунктум ремотум</li><li>Пунктум проксимум</li><li>Всички изброени</li><li>Нито един от посочените</li></ul><p><strong>Неправилният астигматизъм може да се дължи на:</strong></p><ul><li><strong><span style=\"color: rgb(255, 0, 0)\">Всички посочени</span></strong></li><ul><li>Травма</li><li>Кератит</li><li>Кератоконус</li><li>Язва на роговицата</li></ul></ul><p><strong>Физиологичният астигматизъм има стойности между:</strong></p><ul><li><strong><span style=\"color: rgb(255, 0, 0)\">0,5-1 D</span></strong></li><li>1-2 D</li><li>2-3 D</li><li>3-4 D</li><li>Над 5 D</li></ul><p><strong><span class=\"editor-note\" data-note=\"![Image](https://files.coursebook.lol/%D0%9F%D0%B0%D0%B8%D1%81%D0%B8%D0%B9/2026-04-27/text-editor-images/2026/04/1777295051637-image.png &quot;width=100%&quot;)\" id=\"note-1777295052868-0\">Пресбиопията 50-годишен пациент с еметропия, който чете на разстояние 33 см, се коригира приблизително с</span>:</strong></p><ul><li><strong><span style=\"color: rgb(255, 0, 0)\">+2 D</span></strong></li><li>+1 D</li><li>+3 D</li><li>+4 D</li><li>+5 D</li></ul><p><strong>Предно-задната ос на миопичното око е:</strong></p><ul><li><strong><span style=\"color: rgb(255, 0, 0)\">Над 24 мм</span></strong></li><li>24 мм</li><li>Под 24 мм</li><li>Всички посочени</li><li>Нито едно от посочените</li></ul><p><strong>През fissure orbitalis superior навлиза:</strong></p><ul><li><strong><span style=\"color: rgb(255, 0, 0)\">N. oculomotorius</span></strong></li><li>n. opticus</li><li>a. ophthalmica</li><li>n. zygomaticus</li><li>a. infraorbitalis</li></ul><p><strong>При целулит се наблюдават следните симптоми:</strong></p><ul><li><strong><span style=\"color: rgb(255, 0, 0)\">Всички посочени</span></strong></li><ul><li>Оток на клепачите</li><li>Хемоза на конюнктивата</li><li>Ограничение в подвижността на очната ябълка</li><li>Екзофталм</li></ul></ul><p><strong>При деца възпалението на орбитата най-често води началото си от:</strong></p><ul><li><strong><span style=\"color: rgb(255, 0, 0)\">Етмоидални клетки</span></strong></li><li>Максиларен синус</li><li>Фронтален синус</li><li>Зъби</li><li>Всички посочени</li></ul><p><strong>Периостит може да се развие при проникване на инфекция:</strong></p><ul><li><strong><span style=\"color: rgb(255, 0, 0)\">Всички посочени</span></strong></li><ul><li>При травма</li><li>При чуждо тяло</li><li>По съседство</li><li>По кръвен път</li></ul></ul><p><strong>Затварянето на клепачите се осъществява от:</strong></p><ul><li><strong><span style=\"color: rgb(255, 0, 0)\">Клепачната част на m. orbicularis oculi</span></strong></li><li>Орбиталната част на m. orbicularis oculi</li><li>M. levator palpebrae superioris</li><li>Мускул на Мюлер</li><li>Нито един от посочените</li></ul><p><strong>Инервацията на долен прав мускул е от:</strong></p><ul><li><strong><span style=\"color: rgb(255, 0, 0)\">N. oculomotorius</span></strong></li><li>N. abducens</li><li>N. trochlearis</li><li>N. ophthalmicus</li><li>Нито един от посочените</li></ul><p><strong>Дихромазията е:</strong></p><ul><li><strong><span style=\"color: rgb(255, 0, 0)\">Невъзможност за възприемане на един цвят</span></strong></li><li>Невъзможност за възприемане на три цвята</li><li>Невъзможност за възприемане на два цвята</li><li>Нито един от посочените</li><li>Всички посочени</li></ul><p><strong>Границите на зрителното поле за белия цвят са:</strong></p><ul><li><strong><span style=\"color: rgb(255, 0, 0)\">Темпорално 90°, назално 60°, долу 70°, горе 60°</span></strong></li><li>Назално 70°, темпорално 90°, долу 70°, горе 60°</li><li>Горе 90°, назално 60°, горе 70°, темпорално 60°</li><li>Долу 90°, назално 60°, горе 70°, темпорално 60°</li><li>Темпорално 70°, долу 90°, назално 60°, горе 60°</li></ul><p><strong>Миопията се коригира с:</strong></p><ul><li><p><strong><span style=\"color: rgb(255, 0, 0)\">Разсейващи лещи</span></strong></p><br></li><li>Събирателни лещи</li><li>Цилиндрични лещи</li><li>Всички изброени</li><li>Нищо от изброените</li></ul><p><strong>Сляпото петно на Mariotte е проекция на:</strong></p><ul><li><strong><span style=\"color: rgb(255, 0, 0)\"><p>Диска на зрителния нерв</p><br></span></strong></li><li>Макулата</li><li>Кръвоносните съдове</li><li>Органични промени в ретината</li><li>Нито един от посочените</li></ul><p><strong>Концентрично стеснение на зрителното поле се наблюдава при:</strong></p><ul><li><span style=\"color: rgb(255, 0, 0)\"><p><strong>Пигментна дегенерация</strong></p><br></span></li><li>Тумори на хипофизата</li><li>Дегенерация на макулата</li><li>Отлепване на ретината</li><li>При всички изброени</li></ul><p><strong>Angulus minimum separabile е равен на:</strong></p><ul><li><span style=\"color: rgb(255, 0, 0)\"><strong><p>Една минута</p><br></strong></span></li><li>Пет градуса</li><li>Три минути</li><li>Десет минути</li><li>Пет минути</li></ul><p><strong>Посочете пълния отговор: Средната обвивка на окото, която се нарича ……….., е изградена от:</strong></p><ul><li><span style=\"color: rgb(255, 0, 0)\"><strong><p>Хороидея, ирис, цилиарно тяло</p><br></strong></span></li><li>Хороидея, роговица, цилиарно тяло</li><li>Хороидея, ирис, склера</li><li>Хороидея, ирис, ретина</li></ul><p><strong>Посочете пълния отговор. През canalis nervi optici преминават:</strong></p><ul><li><strong><span style=\"color: rgb(255, 0, 0)\">N. opticus, a. ophthalmica</span></strong></li><li>N. ophthalmica, a. ophthalmica</li><li>N. trigeminus, a. ophthalmica</li><li>N. opticus, v. ophthalmica</li></ul><p><strong>M. sphincter pupillae се инервира от:</strong></p><ul><li><strong><span style=\"color: rgb(255, 0, 0)\"><p>парасимпатикус</p><br></span></strong></li><li>n. ophthalmicus</li><li>симпатикус</li><li>nn. ciliares</li></ul><p><strong>Дебелината на ретината в норма варира от ….. до …… мм:</strong></p><ul><li>0,04-0,08 мм</li><li><strong><span style=\"color: rgb(255, 0, 0)\">0,04-0,4 мм</span></strong></li><li>1-6 мм</li><li>0,04-1 мм</li></ul><p><strong><span class=\"editor-note\" data-note=\"![Image](https://files.coursebook.lol/%D0%9F%D0%B0%D0%B8%D1%81%D0%B8%D0%B9/2026-04-27/text-editor-images/2026/04/1777288434826-image.png &quot;width=60%&quot;)\" id=\"note-1777289876989-3\">Водният слой на слъзния филм има следната функция:</span></strong></p><ul><li><strong><span style=\"color: rgb(255, 0, 0)\">осигурява оптичните качества на роговицата</span></strong></li><li>Поддържа стабилността на слъзния филм</li><li>Поддържа сетивността на роговицата</li><li>Осигурява прикрепването на водната фаза към роговичния епител</li></ul><p><strong>Фотопично се нарича зрението:</strong></p><ul><li><strong><span style=\"color: rgb(255, 0, 0)\"><p>при добра сетивност</p><br></span></strong></li><li>при парализа на акомодацията</li><li>при тъмнина</li><li>при сумрак</li></ul><p><strong>Мезопично се нарича зрението:</strong></p><ul><li><strong><span style=\"color: rgb(255, 0, 0)\">При сумрак</span></strong></li><li>При парализа на акомодацията</li><li>При тъмнина</li><li>При добра осветеност</li></ul><p><strong>Скотопично се нарича зрението:</strong></p><ul><li><strong><span style=\"color: rgb(255, 0, 0)\">при тъмнина</span></strong></li><li>при парализа на акомодацията</li><li>при добра осветеност</li><li>при сумрак</li></ul><p><strong>Visus е количествена мярка за определяне на:</strong></p><ul><li><strong><span style=\"color: rgb(255, 0, 0)\"><p>Зрителна острота</p><br></span></strong></li><li>Зрителното поле</li><li>Светлоусещане</li><li>Адаптация</li></ul><p><strong>Биомикроскопията е метод за изследване на:</strong></p><ul><li><strong><span style=\"color: rgb(255, 0, 0)\">роговица</span></strong></li><li>зрителна острота</li><li>зрително поле</li><li>адаптация</li></ul><p><strong>Рефракцията на окото зависи от следните основни анатомични елементи:</strong></p><ul><li><strong><span style=\"color: rgb(255, 0, 0)\"><p>Стъкловидно тяло, леща, роговица</p><br></span></strong></li><li>Роговица, леща, склера</li><li>Леща, стъкловидно тяло, макула</li><li>Леща, стъкловидно тяло, хороидея</li></ul><p><strong>Екзофталмът може да бъде:</strong></p><ul><li><strong><span style=\"color: rgb(255, 0, 0)\"><p>Всички изброени</p><br></span></strong></li><ul><li>Централен</li><li>Редуктабилен</li><li>Интермитентен</li></ul></ul><p><strong><span class=\"editor-note\" data-note=\"![Image](https://files.coursebook.lol/%D0%9F%D0%B0%D0%B8%D1%81%D0%B8%D0%B9/2026-04-27/text-editor-images/2026/04/1777295170270-image.png &quot;width=100%&quot;)\" id=\"note-1777295171577-1\">Вътрешният хордеолум представлява възпаление на</span>:</strong></p><ul><li><strong><span style=\"color: rgb(255, 0, 0)\"><p>Жлезите на Цайс</p><br></span></strong></li><li>Мейбомиевите жлези</li><li>Жлезите на Мол</li><li>Слъзната жлеза</li></ul><p><strong>Триадата фарингит, конюнктивит и треска е характерна за:</strong></p><ul><li><strong><span style=\"color: rgb(255, 0, 0)\">Аденовирусен конюнктивит</span></strong></li><li>Ентеровирусен конюнктивит</li><li>Вернален конюнктивит</li><li>Трахома</li></ul><p><strong>Обемът на орбитата е:</strong></p><ul><li><strong><span style=\"color: rgb(255, 0, 0)\"><p>30 сс</p><br></span></strong></li><li>20 сс</li><li>40 сс</li><li>50 сс</li></ul><p><strong>Външната обвивка на окото е изградена от:</strong></p><ul><li><strong><span style=\"color: rgb(255, 0, 0)\">роговица, склера</span></strong></li><li>хороидея, роговица</li><li>склера, ретина</li><li>роговица, цилиарно тяло</li></ul><p><strong>Част от съдовете и нервите, които преминават през fissura orbitalis superior са:</strong></p><ul><li><strong><span style=\"color: rgb(255, 0, 0)\">N. ophthalmicus, v. ophthalmica</span></strong></li><li>N. opticus, a. ophthalmica</li><li>N. ophthalmicus, a. ophthalmica</li><li>N. opticus, v. ophthalmica</li></ul><p><strong>Пречупващата сила на роговицата при млади хора може да се променя от …. до….:</strong></p><ul><li><strong><span style=\"color: rgb(255, 0, 0)\">18-40 D</span></strong></li><li>18-33 D</li><li>10-20 D</li><li>не се променя</li></ul><p><strong>M. dilatators pupillae се инервира от:</strong></p><ul><li><strong><span style=\"color: rgb(255, 0, 0)\">симпатикус</span></strong></li><li>n. ophthalmicus</li><li>парасимпатикус</li><li>nn. ciliares</li></ul><p><strong>Основните функции на периферната част на ретината са:</strong></p><ul><li><strong><span style=\"color: rgb(255, 0, 0)\">чувствителна на слаба светлина, детекция на движението, скотопично зрение</span></strong></li><li>чувствителна на слаба светлина, детекция на движението, фино зрение</li><li>чувствителна на слаба светлина, детекция на движението, централно зрение</li><li>чувствителна на слаба светлина, детекция на движението, цветно зрение</li></ul><p><strong>Орбикуларният мускул се инервира от:</strong></p><ul><li><strong><span style=\"color: rgb(255, 0, 0)\">N. facialis</span></strong></li><li>N. oculomotorius</li><li>N. trochlearis</li><li>N. abducens</li></ul><p><strong>Адаптацията е физиологичен механизъм:</strong></p><ul><li><strong><span style=\"color: rgb(255, 0, 0)\">Приспособяващ окото за виждане при различни светлинни условия</span></strong></li><li>Приспособяващ окото за ясно виждане на далеч и на близо</li><li>Приспособяващ окото за ясно виждане при парализа на акомодацията</li><li>Приспособяващ окото за различаване на цветовете</li></ul><p><strong>Акомодацията е физиологичен механизъм:</strong></p><ul><li><strong><span style=\"color: rgb(255, 0, 0)\"><p>Приспособяващ окото за ясно виждане на далеч и на близо</p><br></span></strong></li><li>Приспособяващ окото за виждане при различни светлинни условия</li><li>Приспособяващ окото за ясно виждане на тъмно</li><li>Приспособяващ окото за различаване на цветовете</li></ul><p><strong>Видими са лъчите от електромагнитния спектър с дължина на вълната:</strong></p><ul><li><strong><span style=\"color: rgb(255, 0, 0)\">380-760 nm</span></strong></li><li>260-380 nm</li><li>580-760 nm</li><li>680-760 nm</li></ul><p><strong>Периметрията е метод за изследване на:</strong></p><ul><li><strong><span style=\"color: rgb(255, 0, 0)\">зрително поле</span></strong></li><li>роговица</li><li>зрителна острота</li><li>адаптация</li></ul><p><strong>Хиперметропията е рефракция, при която успоредните лъчи се получават:</strong></p><ul><li><strong><span style=\"color: rgb(255, 0, 0)\">зад ретината</span></strong></li><li>пред ретината</li><li>има два главни фокуса</li><li>върху ретината</li></ul><p><strong>Пулсиращ екзофталм се наблюдава при:</strong></p><ul><li><strong><span style=\"color: rgb(255, 0, 0)\"><p>каротидо-кавернозна фистула</p><br></span></strong></li><li>варици на орбитата</li><li>целулит</li><li>периостит на орбитата</li></ul><p><strong>Субепителни инфилтрати се появяват при:</strong></p><ul><li><span style=\"color: rgb(255, 0, 0)\"><strong>епидемичен кератоконюнктивит</strong></span></li><li><p>вернален конюнктивит</p><br></li><li>ентеровирусен конюнктивит</li><li>трахома</li></ul><p><strong>Дължината на предно-задната ос на орбитата (от входа до върха й) е:</strong></p><ul><li><strong><span style=\"color: rgb(255, 0, 0)\">45 мм</span></strong></li><li>35 мм</li><li>25 мм</li><li>55 мм</li></ul><p><strong>Най-вътрешната обвивка на окото е изградена от:</strong></p><ul><li><strong><span style=\"color: rgb(255, 0, 0)\">ретина</span></strong></li><li>хороидея</li><li>леща</li><li>цилиарно тяло</li></ul><p><strong>Дебелината на роговицата в централната й част в норма е:</strong></p><ul><li><strong><span style=\"color: rgb(255, 0, 0)\"><p>530-550 µm</p><br></span></strong></li><li>430-450 µm</li><li>630-650 µm</li><li>330-550 µm</li></ul><p><strong>Основните функции на макулата са:</strong></p><ul><li><strong><span style=\"color: rgb(255, 0, 0)\"><p>чувствителна на силна светлина, цветно зрение, централно зрение</p><br></span></strong></li><li>чувствителна на силна светлина, мезопично зрение, цветно зрение</li><li>чувствителна на силна светлина, централно зрение, скотопично зрение</li><li>чувствителна на силна светлина, фотопично зрение, мезопично</li></ul><p><strong><span class=\"editor-note\" data-note=\"# И двата се верни според учебника им :D\n![Image](https://files.coursebook.lol/%D0%9F%D0%B0%D0%B8%D1%81%D0%B8%D0%B9/2026-04-27/text-editor-images/2026/04/1777288434826-image.png &quot;width=60%&quot;)\" id=\"note-1777288454338-0\">Музинозният слой на слъзния филм има следната функция:</span></strong></p><ul><li><strong><span style=\"color: rgb(255, 0, 0)\"><p>Осигурява прикрепването на водната фаза към роговичния епител</p><br></span></strong></li><li><span style=\"color: rgb(255, 0, 0)\">Поддържа стабилността на слъзния филм</span></li><li>Поддържа сетивността на роговицата</li><li>Осигурява оптичните качества на роговицата</li></ul><p><strong>Морфологичен субстрат на акомодацията са:</strong></p><ul><li><strong><span style=\"color: rgb(255, 0, 0)\">цилиарен мускул, леща</span></strong></li><li>цилиарен мускул, роговица</li><li>роговица, леща</li><li>леща, стъкловидно тяло</li></ul><p><strong>За нормална се приема позицията на очната ябълка при резултат от екзофталмометрията:</strong></p><ul><li><strong><span style=\"color: rgb(255, 0, 0)\">12-15 мм</span></strong></li><li>10-12 мм</li><li>13-14 мм</li><li>над 20 мм</li></ul><p><strong>Трихромазията се нарича:</strong></p><ul><li><strong><span style=\"color: rgb(255, 0, 0)\">невъзприемане на трите основни цвята</span></strong></li><li>невъзпаление на един основен цвят</li><li>невъзприемане на два основни цвята</li><li>нормално възприемане на цветовете (<span style=\"color: rgb(0, 176, 80)\">трихромати</span>)</li></ul><p><strong>Астигматизмът е рефракционна аномалия, при която успоредните лъчи се фокусират:</strong></p><ul><li><strong><span style=\"color: rgb(255, 0, 0)\">има два главни фокуса</span></strong></li><li>пред ретината</li><li>зад ретината</li><li>върху ретината</li></ul><p><strong>Екзофталмът не може да се дължи на:</strong></p><ul><li><strong><span style=\"color: rgb(255, 0, 0)\">повишено вътреочно налягане</span></strong></li><li>целулит</li><li>тумор в орбитата</li><li>варици на орбитата</li></ul><p><strong>Базоцелуларният карцином на клепача:</strong></p><ul><li><strong><span style=\"color: rgb(255, 0, 0)\">има инфилтративен растеж</span></strong></li><li>е най-рядко срещания злокачествен клепачен тумор</li><li>дава далечни метастази</li><li>рядко редидивира</li></ul><p><strong>Дъговидно извит миглен ръб с увиснала надолу темпорална част (S-форма), се наблюдава при:</strong></p><ul><li><strong><span style=\"color: rgb(255, 0, 0)\"><p>остър дакриоаденит</p><br></span></strong></li><li>хроничен дакриоцистит</li><li>остър дакриоцистит</li><li>всички посочени</li></ul><p><strong>За пролетния катар (вернален конюнктивит) не е вярно, че:</strong></p><ul><li><strong style=\"color: rgb(255, 0, 0)\">се лекува с антибиотици</strong></li><li><p>засяга по-често момчета</p><br></li><li>се характеризира с папиларна хиперплазия на тарзалната конюнктива</li><li>се лекува с кортикостероиди</li></ul><p><strong>При тумор на хипофизата дефектите в зрителното поле са:</strong></p><ul><li><strong><span style=\"color: rgb(255, 0, 0)\">хетеронимна хемианопсия</span></strong></li><li>хомонимна хемианопсия</li><li>квадрантопсии</li><li>скотоми</li></ul><p><strong>Морфологичен субстрат на централното зрение в ретината са:</strong></p><ul><li><strong><span style=\"color: rgb(255, 0, 0)\">конусчета</span></strong></li><li>пръчици и конусчета</li><li>пръчици</li><li>пигментен епител</li></ul><p><strong>Основна функция на ендотела на роговицата е:</strong></p><ul><li><strong><span style=\"color: rgb(255, 0, 0)\"><p>да поддържа дехидратацията на роговицата</p><br></span></strong></li><li>да пречупва светлината</li><li>да поддържа роговицата гладка</li><li>да поддържа нормалната сетивност на роговицата</li></ul><p><strong>Еметропията е рефракция, при която образът се фокусира:</strong></p><ul><li><strong><span style=\"color: rgb(255, 0, 0)\">върху ретината</span></strong></li><li>зад ретината</li><li>има два главни фокуса</li><li>пред ретината</li></ul><p><strong>В зависимост от етиологията си, ектропионът бива:</strong></p><ul><li><strong><span style=\"color: rgb(255, 0, 0)\">всички посочени</span></strong></li><ul><li>инволутивен</li><li>цикатрициален</li><li>паралитичен</li></ul></ul><p><strong>Персистиращата мембрана на Хаснер клинично се проявява с:</strong></p><ul><li><strong><span style=\"color: rgb(255, 0, 0)\">дакриоцистит на новороденото</span></strong></li><li>остър дакриоаденит</li><li>хроничен дакриоаденит</li><li>хроничен дакриоцистит</li></ul><p><strong>За гонококов конюнктивит на новороденото са характерни всички симптоми, с изкл. на:</strong></p><ul><li><strong><span style=\"color: rgb(255, 0, 0)\">инкубационен период 10-14 дни</span></strong></li><li>силно изразен твърд оток на клепачите</li><li>гноен секрет</li><li>липса на фоликули</li></ul><p><strong>Клиничната картина при бактериален кератит включва:</strong></p><ul><li><strong><span style=\"color: rgb(255, 0, 0)\">всичко изброено</span></strong></li><ul><li>болка, фотофобия</li><li>инфилтрат в роговицата</li><li>инекция</li></ul></ul><p><strong>Най-често срещаната патология на лещата е:</strong></p><ul><li><strong><span style=\"color: rgb(255, 0, 0)\">катаракта</span></strong></li><li>вродена афакия</li><li>сублуксация</li><li>травматична луксация</li></ul><p><strong>Преципитатите по роговичния ендотел са характерен признак на:</strong></p><ul><li><strong><span style=\"color: rgb(255, 0, 0)\">иридоциклит</span></strong></li><li>заден увеит</li><li>интермедиерен увеит</li><li>еписклерит</li></ul><p><strong>В макулната област се наблюдава т.нар. „черешова точка” при:</strong></p><ul><li><strong><span style=\"color: rgb(255, 0, 0)\">стволова оклузия на a. centralis retinae</span></strong></li><li>клонова оклузия на a. centralis retinae</li><li>клонова оклузия на v. centralis retinae</li><li>стволова оклузия на v. centralis retinae</li></ul><p><strong>Рисков фактор за появата на диабетна ретинопатия е:</strong></p><ul><li><strong><span style=\"color: rgb(255, 0, 0)\">всички посочени</span></strong></li><ul><li>продължителността на диабета</li><li>лош гликемичен контрол</li><li>хипертонията</li></ul></ul><p><strong>При липса на диабетна ретинопатия, диабетиците със ЗД тип 1 трябва да бъдат преглеждани от офталмолог:</strong></p><ul><li><strong><span style=\"color: rgb(255, 0, 0)\">веднъж годишно след мидриаза</span></strong></li><li>на две години след мидриаза</li><li>от няколко месеца до веднъж годишно след мидриаза</li><li>на 3 месеца след мидриаза</li></ul><p><strong><span class=\"editor-note\" data-note=\"![Image](https://files.coursebook.lol/%D0%9F%D0%B0%D0%B8%D1%81%D0%B8%D0%B9/2026-04-27/text-editor-images/2026/04/1777289397851-image.png &quot;width=100%&quot;)\" id=\"note-1777289503723-2\">Съвременното лечение на ексудативната форма на макулната дегенерация, свързана с възрастта е:</span></strong></p><ul><li><strong><span style=\"color: rgb(255, 0, 0)\">с анти-VEGF медикаменти</span></strong></li><li>с лазер</li><li>с антиоксиданти</li><li>не се лекува</li></ul><p><strong>Застойната папила е резултат от:</strong></p><ul><li><strong><span style=\"color: rgb(255, 0, 0)\">повишено интракраниално налягане</span></strong></li><li>възпаление</li><li>повишено вътреочно налягане</li><li>всичко изброено</li></ul><p><strong>„Бяло око”, незачервено, с бързо настъпило понижение на зрителната острота, е симптом на:</strong></p><ul><li><strong><span style=\"color: rgb(255, 0, 0)\">оклузия на вена централис ретине</span></strong></li><li>макулна дегенерация</li><li>катаракта</li><li>дистрофии на роговицата</li></ul><p><strong>Червено око с понижение на зрителната острота е симптом на:</strong></p><ul><li><strong><span style=\"color: rgb(255, 0, 0)\">иридоциклит</span></strong></li><li>еписклерит</li><li>конюнктивит</li><li>блефарит</li></ul><p><strong>Бета-блокерите:</strong></p><ul><li><strong><span style=\"color: rgb(255, 0, 0)\">намаляват продукцията на вътреочна течност</span></strong></li><li>подобряват увеосклералния оток</li><li>намаляват продукцията и подобряват увеосклералния оток</li><li>подобряват отока в камерния ъгъл</li></ul><p><strong>Ранни симптоми при вродена (конгенитална) глаукома са:</strong></p><ul><li><strong><span style=\"color: rgb(255, 0, 0)\">всичко изброено</span></strong></li><ul><li>фотофобия, сълзене</li><li>повишено вътреочно налягане</li><li>увеличен размер на роговицата</li></ul></ul><p><strong>Причини за конкомитентен страбизъм могат да бъдат:</strong></p><ul><li><strong><span style=\"color: rgb(255, 0, 0)\"><p>рефрактерни аномалии</p><br></span></strong></li><li>всичко изброено</li><li>парализа на черепномозъчен нерв</li><li>увеит</li></ul><p><strong>Диабетната ретинопатия започва с:</strong></p><ul><li><strong><span style=\"color: rgb(255, 0, 0)\">микрохеморагии, микроаневризми и оток в ретината</span></strong></li><li>неоваскуларизация</li><li>внезапно понижение на зрението</li><li>всичко изброено</li></ul><p><strong>Откритоъгълната глаукома е заболяване, което протича:</strong></p><ul><li><strong><span style=\"color: rgb(255, 0, 0)\"><p>с промени в зрителния нерв и в зрителното поле</p><br></span></strong></li><li>всичко изброено</li><li>с оток на роговицата и повишено вътреочно налягане</li><li>пристъпно</li></ul><p><strong>Ерозиите на роговицата са:</strong></p><ul><li><strong><span style=\"color: rgb(255, 0, 0)\">увреждания на епитела на роговицата</span></strong></li><li>нарушения в цялата роговична дебелина</li><li>гънки на Десцеметовата мембрана</li><li>увреждания на стромата на роговицата</li></ul><p><strong>Бързо настъпило понижение на зрителната острота е симптом на:</strong></p><ul><li><strong><span style=\"color: rgb(255, 0, 0)\"><p>отлепване на ретината</p><br></span></strong></li><li>всичко посочено</li><li>макулна дегенерация</li><li>дистрофии на роговицата</li></ul><p><strong>Червено око, без понижение на зрителната острота, е симптом на:</strong></p><ul><li><strong><span style=\"color: rgb(255, 0, 0)\">конюнктивит</span></strong></li><li>кератит</li><li>иридоциклит</li><li>всичко посочено</li></ul><p><strong>Парасимпатикомиметиците:</strong></p><ul><li><strong><span style=\"color: rgb(255, 0, 0)\">подобряват отока на вътреочна течност в камерния ъгъл</span></strong></li><li>намаляват продукцията на вътреочна течност</li><li>подобряват увеосклералния оток</li><li>намаляват продукцията и подобряват увеосклералния оток</li></ul><p><strong>Причини за съдружно кръвогледство могат да бъдат:</strong></p><ul><li><strong><span style=\"color: rgb(255, 0, 0)\">всичко изброено</span></strong></li><ul><li>катаракта</li><li>ретинобластом</li><li>хиперметропия</li></ul></ul><p><strong>Закритоъгълната глаукома протича с:</strong></p><ul><li><strong><span style=\"color: rgb(255, 0, 0)\">всичко изброено</span></strong></li><ul><li>повишено вътреочно налягане</li><li>оток на роговицата и широка зеница</li><li>плитка предна камера</li></ul></ul><p><strong>„Сухо око” може да бъде резултат от:</strong></p><ul><li><p><strong><span style=\"color: rgb(255, 0, 0)\">блефарит</span></strong></p><br></li><li>всичко изброено</li><li>първична откритоъгълна глаукома</li><li>парализа на n. oculomotorius</li></ul><p><strong>За амблиопията е вярно, че:</strong></p><ul><li><strong><span style=\"color: rgb(255, 0, 0)\">всичко изброено</span></strong></li><ul><li>е функционално понижение на зрителната острота</li><li>настъпва до 7-годишна възраст</li><li>не се коригира с очила и други оптични средства</li></ul></ul><p><strong>Съвременна техника за оперативно лечение на катаракта е:</strong></p><ul><li><strong><span style=\"color: rgb(255, 0, 0)\"><p>факоемулсификация</p><br></span></strong></li><li>всички посочени</li><li>екстракапсулна екстракция</li><li>интракапсулна екстракция</li></ul><p><strong>Дисциморфен кератит се наблюдава при:</strong></p><ul><li><strong><span style=\"color: rgb(255, 0, 0)\"><p>херпес симплекс инфекция</p><br></span></strong></li><li>всички посочени</li><li>епидемичен кератоконюнктивит</li><li>херпес зостер инфекция</li></ul><p><strong>Първа помощ при химични изгаряния на очите включва:</strong></p><ul><li><strong><span style=\"color: rgb(255, 0, 0)\">промивка</span></strong></li><li>неутрализация</li><li>превръзка</li><li>всичко изброено</li></ul><p><strong><span class=\"editor-note\" data-note=\"![Image](https://files.coursebook.lol/%D0%9F%D0%B0%D0%B8%D1%81%D0%B8%D0%B9/2026-04-27/text-editor-images/2026/04/1777289397851-image.png &quot;width=100%&quot;)\" id=\"note-1777289429688-1\">Сухата форма на макулна дегенерация, свързана с възрастта, се лекува с:</span></strong></p><ul><li><strong><span style=\"color: rgb(255, 0, 0)\">антиоксиданти</span></strong></li><li>лазер</li><li>анти-VEGF медикаменти</li><li>не се лекува (<span style=\"color: rgb(0, 176, 80)\">може би и това</span>)</li></ul><p><strong>Първият скринингов преглед за ретинопатия на недоносеното се извършва на:</strong></p><ul><li><strong><span style=\"color: rgb(255, 0, 0)\">2-4 седмица след раждането</span></strong></li><li>шестия месец след раждането</li><li>веднага след раждането</li><li>третия месец след раждането</li></ul><p><strong>Червено око без понижение на зрителната острота е симптом на:</strong></p><ul><li><strong><span style=\"color: rgb(255, 0, 0)\">блефарит</span></strong></li><li>кератит</li><li>глаукомен пристъп</li><li>иридоциклит</li></ul><p><strong>Капсулата на лещата е най-тънка в:</strong></p><ul><li><strong><span style=\"color: rgb(255, 0, 0)\">областта на заден полюс</span></strong></li><li>нито едно от посочените</li><li>екваториална област</li><li>областта на преден полюс</li></ul><p><strong>Роговични дистрофии са:</strong></p><ul><li><strong><span style=\"color: rgb(255, 0, 0)\">макуларна и грануларна</span></strong></li><li>грануларна</li><li>макуларна</li><li>нито една от посочените</li></ul><p><strong>Роговичните дистрофии обикновено са:</strong></p><ul><li><strong><span style=\"color: rgb(255, 0, 0)\">вродени двустранни</span></strong></li><li>придобити двустранни</li><li>нито едно от посочените</li><li>придобити едностранни</li></ul><p><strong>Кой външен очедвигателен мускул има най-късо сухожилие:</strong></p><ul><li><strong><span style=\"color: rgb(255, 0, 0)\">медиален прав мускул</span></strong></li><li>латерален прав мускул</li><li>горен кос мускул</li><li>долен кос мускул</li></ul><p><strong>Артериалната хипертония причинява:</strong></p><ul><li><strong><span style=\"color: rgb(255, 0, 0)\"><p>промени в съдовете и циркулацията на ретината и хориоидеята</p><br></span></strong></li><li>всичко изброено</li><li>внезапно понижение на зрението</li><li>силна болка в окото и повишено налягане</li></ul><p><strong>Простагландиновите аналози:</strong></p><ul><li><strong><span style=\"color: rgb(255, 0, 0)\">подобряват увеосклералния оток</span></strong></li><li>намаляват продукцията на вътреочна течност</li><li>подобряват отока на камерната течност през трабекуларната мрежа</li><li>намаляват продукцията и подобряват увеосклералния отток</li></ul><p><strong>Усложнение на късогледството е?</strong></p><ul><li><strong><span style=\"color: rgb(255, 0, 0)\">Фуксово петно</span></strong></li><li>дихромазия</li><li>битемпорална хемианопсия</li><li>монохромазия</li><li>нито едно от изброените</li></ul><h2>Отворени въпроси</h2><p><strong>Дайте определение на:</strong></p><ul><li><strong>Оптопити се наричат:</strong> \n<p>Стандартизирани знаци (букви, цифри, фигури), използвани за изследване на зрителната острота, подредени в таблици с намаляващ размер (напр. таблицата на Снелен), където всеки ред отговаря на определено разстояние за нормално зрение.</p></li><li><strong><span class=\"editor-note\" data-note=\"&quot;кокоша слепота&quot;\" id=\"note-1777348568175-2\">Никталопия</span> е: \n</strong><p>Силно затруднено или невъзможно виждане при слаба светлина, често при дефицит на витамин А или дегенеративни заболявания на ретината (напр. ретинитис пигментоза).</p><strong>\n</strong></li><li><strong>Дистопия на очната ябълка е:\n</strong><p>Изместване на окото от нормалната му позиция в орбитата (без издаване напред), обикновено в хоризонтална или вертикална посока, най-често поради тумори, кисти или орбитални фрактури.</p><i>\n</i></li><li><strong>Ентропион е:\n</strong><p>Завъртане на клепачния ръб навътре към очната ябълка, при което миглите и кожата се трият в роговицата и конюнктивата, причинявайки дразнене, болка, зачервяване и риск от роговични язви.</p><i>\n</i></li></ul><p><strong>Дайте кратък отговор на следните въпроси:</strong></p><ul><li><p style=\"font-weight: bold\">Снемането на офталмологичния статус на всеки пациент следва определена </p><p style=\"font-weight: bold\">последователност, наречена СИСТЕМЕН ХОД НА ОЧНОТО ИЗСЛЕДВАНЕ. </p><p><strong>Посочете последователността на изследването:\n</strong></p><p>В хода на </p><p>прегледа се допълват и данните от първоначалната снета анамнеза и се изследват:\n</p><p>Функционални изследвания: Първо се изследват зрителна острота, периферно зрение, двуочно зрение, очна подвижност, адаптация, светлоусещане и цветоусещане.\n</p><p>Анатомичен преглед (по повърхностно-дълбочинен ред): </p><p>Орбита, </p><p>Клепачи, </p><p>Слъзен апарат, </p><p>Двигателен апарат на окото, </p><p>Конюнктива, </p><p>Роговица, </p><p>Предна камера, </p><p>Ирис, </p><p>Зеница, </p><p>Леща, </p><p>Стъкловидно тяло, </p><p>Очно дъно\n</p><p>Специални методи и задължителни апаратни изследвания: </p><p><span class=\"editor-note\" data-note=\"Детайлен оглед на преден очен сегмент: конюнктива, роговица, предна камера, ирис, зеница и леща.\" id=\"note-1777348304268-0\">Биомикроскопия</span> и </p><p><span class=\"editor-note\" data-note=\"Изследване на заден очен сегмент: стъкловидно тяло и очно дъно,\" id=\"note-1777348316750-1\">Офталмоскопия</span>.</p><br></li></ul><p><strong>Обяснете какво означава:</strong></p><ul><li><strong>Visus oculi dextri (VOD) = 1,0: \n</strong><p>Зрителната острота на дясното око е напълно запазена (100%).</p></li><li><strong>Visus oculi sinistra (VOS) = 0,5:\n</strong><p>Зрителната острота на лявото око е наполовина запазена (50%). Пациентът вижда на 5 метра това, което нормалното око вижда от 10 метра.</p><strong>\n</strong></li><li><strong>Visus oculi utr. (VOU) = 0,25:\n</strong><p>Зрителната острота на двете очи едновременно (бинокулярно) е 25% от нормата.</p><strong>\n</strong></li></ul><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\"><h1 style=\"text-align: center\">Още възмножни въпроси</h1><p><strong>Кампиметрията е метод за изследване на зрителното поле?</strong></p><ul><li><strong><span style=\"color: rgb(255, 0, 0)\">на плосък екран</span></strong></li></ul><p><strong>Прозрачни, пречупващи среди на окото са?</strong></p><ul><li><strong><span style=\"color: rgb(255, 0, 0)\">роговица, леща и стъкловидно тяло</span></strong></li></ul><p><strong>От сухожилния пръстен на върха на орбитата започват външните очни мускули с изключение на ?</strong></p><ul><li><strong><span style=\"color: rgb(255, 0, 0)\">m. obliquus inferior</span></strong></li></ul><p><strong>В сетивната инервация на зрителния орган участват?</strong></p><ul><li><strong><span style=\"color: rgb(255, 0, 0)\">n. ophthalmicus (клон на n. trigeminus)</span></strong></li></ul><p><strong>Папилата на зрителния нерв в норма е с диаметър?</strong></p><ul><li><strong><span style=\"color: rgb(255, 0, 0)\">1,5 мм</span></strong></li></ul><p><strong>Липидния слой на слъзния филм има следната функция?</strong></p><ul><li><strong><span style=\"color: rgb(255, 0, 0)\">поддържа стабилността на слъзния филм</span></strong></li></ul><p><strong>Морфологичен субстрат на абсолютната светлочувствителност са?</strong></p><ul><li><strong><span style=\"color: rgb(255, 0, 0)\">пръчиците</span></strong></li></ul><p><strong>Признак на Мънсон се наблюдава при?</strong></p><ul><li><strong><span style=\"color: rgb(255, 0, 0)\">кератоконус</span></strong></li></ul><p><strong>Тракционното отлепване на ретината най-често се наблюдава при?</strong></p><ul><li><strong><span style=\"color: rgb(255, 0, 0)\">пролиферативна диабетна ретинопатия, ретинопатия на недоносеното</span></strong></li></ul><p><strong>Инхибиторите на карбоанхидразата?</strong></p><ul><li><strong><span style=\"color: rgb(255, 0, 0)\">намаляват продукцията на вътреочна течност</span></strong></li></ul><p><strong>При еметропия пунктум ремотум се намира?</strong></p><ul><li><strong><span style=\"color: rgb(255, 0, 0)\">в безкрайността</span></strong></li></ul><p><strong>Метаморфопсии могат да се появят при:</strong></p><ul><li><strong><span style=\"color: rgb(255, 0, 0)\">заден увеит</span></strong></li></ul><p><strong>Латералната стена на орбитата е формирана от:</strong></p><ul><li><strong><span style=\"color: rgb(255, 0, 0)\">зигоматичната кост и по-голямото крило на сфеноидалната кост</span></strong></li></ul><p><strong>Кортикостероидите са контраиндицирани при:</strong></p><ul><li><strong><span style=\"color: rgb(255, 0, 0)\">дендритна язва</span></strong></li></ul><p><strong>Клетките, които се засягат при увреждане на зрителния нерв при глаукома са:</strong></p><ul><li><strong><span style=\"color: rgb(255, 0, 0)\">ганглийни клетки</span></strong></li></ul><p><strong>Вътреочната течност се секретира от:</strong></p><ul><li><strong><span style=\"color: rgb(255, 0, 0)\">цилиарните израстъци в задната камера</span></strong></li></ul><p><strong>Синя склера се наблюдава при:</strong></p><ul><li><strong><span style=\"color: rgb(255, 0, 0)\">остеогенезис имперфекта</span></strong></li></ul><p><strong>Коя техника е най-малко полезна за оценка на вида на зрителния нерв:</strong></p><ul><li><strong><span style=\"color: rgb(255, 0, 0)\">индиректна офталмоскопия с 20D леща</span></strong></li></ul><p><strong>В коя структура се наблюдава папиларната реакция:</strong></p><ul><li><strong><span style=\"color: rgb(255, 0, 0)\">конюнктива</span></strong></li></ul><p><strong>Предно-задният размер на очната ябълка при възрастен човек е:</strong></p><ul><li><strong><span style=\"color: rgb(255, 0, 0)\">24 мм</span></strong></li></ul><p><strong>След травма има риск от развитие на кой вид глаукома:</strong></p><ul><li><strong><span style=\"color: rgb(255, 0, 0)\">глаукома с рецесия на камерния ъгъл</span></strong></li></ul><p><strong>Кой мускул инервира шести черепномозъчен нерв:</strong></p><ul><li><strong><span style=\"color: rgb(255, 0, 0)\">латерален прав мускул</span></strong></li></ul><p><strong>Червено око без понижение на зрителната острота е симптом на:</strong></p><ul><li><strong><span style=\"color: rgb(255, 0, 0)\">блефарит и конюнктивит</span></strong></li></ul><p><strong>Акомодацията е физиологичен механизъм:</strong></p><ul><li><strong><span style=\"color: rgb(255, 0, 0)\">за усилване на пречупвателната сила на окото при млади хора</span></strong></li></ul><p><strong>Базоцелуларен карцином разположен в коя област се асоциира с лоша прогноза и рецидив:</strong></p><ul><li><strong><span style=\"color: rgb(255, 0, 0)\">медиалния кант на клепача</span></strong></li></ul><p><strong>Терминът анизометропия означава:</strong></p><ul><li><strong><span style=\"color: rgb(255, 0, 0)\">разлика в рефракцията на двете очи</span></strong></li></ul><p><strong>Какъв лазер се използва за менажиране на вторична катаракта:</strong></p><ul><li><strong><span style=\"color: rgb(255, 0, 0)\">Nd:YAG</span></strong></li></ul><p><strong>\"Бяло око\" (незачервено) с остро намаление на зрението и централен скотом са симптоми типични за:</strong></p><ul><li><strong><span style=\"color: rgb(255, 0, 0)\">ретробулбарен неврит</span></strong></li></ul><p><strong><strong>\"Бяло око\" (незачервено) с бавно постепенно понижение на зрителната острота е симптом на:</strong></strong></p><ul><li><strong><strong><span style=\"color: rgb(255, 0, 0)\">откритоъгълна глаукома</span></strong></strong></li></ul><p><strong>От кой нерв се инервира медиалния прав мускул:</strong></p><ul><li><strong><span style=\"color: rgb(255, 0, 0)\">трети ЧМН</span> </strong>(n. oculomotorius)</li></ul><p><strong>Най-тънката стена на орбитата е:</strong></p><ul><li><strong><span style=\"color: rgb(255, 0, 0)\">медиална стена</span></strong></li></ul><p><strong>По кой слой на роговицата се откриват роговичните преципитати:</strong></p><ul><li><strong><span style=\"color: rgb(255, 0, 0)\">ендотел</span></strong></li></ul><p><strong>Острият хеморагичен конюнктивит се причинява от:</strong></p><ul><li><strong><span style=\"color: rgb(255, 0, 0)\">ентеровируси</span></strong></li></ul><p><strong>За заболяването кератоконус е вярно всичко освен:</strong></p><ul><li><strong><span style=\"color: rgb(255, 0, 0)\">задебеляване на роговицата</span></strong></li></ul><p><strong>Друзи се наблюдават при кое от посочените:</strong></p><ul><li><strong><span style=\"color: rgb(255, 0, 0)\">макулна дегенерация, свързана с възрастта</span></strong></li></ul><p><strong>При стволова оклузия на v. centralis retinae не се наблюдава:</strong></p><ul><li><strong><span style=\"color: rgb(255, 0, 0)\">„черешова точка“ в макулата</span></strong></li></ul><p><strong>Зрителният нерв се състои от:</strong></p><ul><li><strong><span style=\"color: rgb(255, 0, 0)\">аксоните на ганглийните клетки</span></strong></li></ul><p><strong>Регматогенно отлепване на ретината:</strong></p><ul><li><strong><span style=\"color: rgb(255, 0, 0)\">се причинява от ретинална руптура и навлизане на течност между невроепитела и пигментния епител</span></strong></li></ul><p><strong>Долният прав мускул се инервира от:</strong></p><ul><li><strong><span style=\"color: rgb(255, 0, 0)\">n. oculomotorius</span></strong></li></ul><p><strong>Стъкловидното тяло съдържа приблизително:</strong></p><ul><li><strong><span style=\"color: rgb(255, 0, 0)\">98% вода</span></strong></li></ul><p><strong>Кератоконусът може да се диагностицира чрез:</strong></p><ul><li><strong><span style=\"color: rgb(255, 0, 0)\">роговична топография</span></strong></li></ul><p><strong>Нормалните стойности на вътреочното налягане са:</strong></p><ul><li><strong><span style=\"color: rgb(255, 0, 0)\">10–21 mmHg</span></strong></li></ul><p><strong>Пациенти с първична закритоъгълна глаукома имат:</strong></p><ul><li><strong><span style=\"color: rgb(255, 0, 0)\">всички изброени</span></strong></li></ul><p><strong>Гоблетовите клетки се намират в:</strong></p><ul><li><strong><span style=\"color: rgb(255, 0, 0)\">конюнктива</span></strong></li></ul><p><strong>Каква енергия се използва при фрагментация на ядрото в операция на катаракта:</strong></p><ul><li><strong><span style=\"color: rgb(255, 0, 0)\">ултразвукова</span></strong></li></ul><p><strong>Морфологичен субстрат на акомодацията са:</strong></p><ul><li><strong><span style=\"color: rgb(255, 0, 0)\">цилиарно тяло, леща</span></strong></li></ul><p><strong>Колко неврона от зрителния път са разположени в ретината:</strong></p><ul><li><strong><span style=\"color: rgb(255, 0, 0)\">3</span></strong></li></ul><p><strong>Златен стандарт за лечението на диабетната ретинопатия е:</strong></p><ul><li><strong><span style=\"color: rgb(255, 0, 0)\">лазерна фотокоагулация</span></strong></li></ul><p><br></p><br><br><p><br></p><p><br></p><br><br><br><style></p><p>    body { </p><p>      font-family: \"Open Sans\", Arial, sans-serif; </p><p>      max-width: 1200px; </p><p>      margin: 2rem auto; </p><p>      padding: 0 1rem; </p><p>      line-height: 1.6; </p><p>      color: #1f2937; </p><p>    }</p><p>    h1 { </p><p>      font-weight: 600; </p><p>      font-size: 1.5em;</p><p>      margin-top: 1.5em;</p><p>      margin-bottom: 0.5em;</p><p>      color: #3a5a40;</p><p>      border-bottom: 2px dashed #a3b18a;</p><p>      padding-bottom: 5px;</p><p>    }</p><p>    p { </p><p>      margin: 0.7em 0 1.5em 0; </p><p>      white-space: pre-wrap;</p><p>    }</p><p>    @media (max-width: 768px) {</p><p>      body { font-size: 16px; }</p><p>      h1 { font-size: 1.3em; }</p><p>    }</p><p>  </style>\n<script src=\"https://cdn.jsdelivr.net/npm/katex@0.16.4/dist/katex.min.js\"></script>\n<script src=\"https://cdn.jsdelivr.net/npm/katex@0.16.4/dist/contrib/auto-render.min.js\"></script>\n<script>\nrenderMathInElement(document.body, {\n  delimiters: [\n    {left: '$$', right: '$$', display: true},\n    {left: '$', right: '$', display: false},\n    {left: '\\\\[', right: '\\\\]', display: true},\n    {left: '\\\\(', right: '\\\\)', display: false}\n  ],\n  throwOnError: false\n});\n</script>\n</body>\n</html>";
